#重点复习：三种方法 1. dfs 2. dijkstra 3. bellman
class Solution:
    def minCost(self, maxTime, edges, passingFees):
        n = len(passingFees)
        g = [[] for _ in range(n)]
        for x, y, t in edges:
            g[x].append((y, t, passingFees[y]))
            g[y].append((x, t, passingFees[x]))
        
        def dfs(x, time, cost):
            if time > maxTime:
                return False
            if cost > mid:
                return False
            if x == n-1:
                return True
            vis[x] = 1
            for y, dt, dc in g[x]:
                if vis[y] == 0:
                    if dfs(y, time+dt, cost+dc):
                        return True
            vis[x] = 0 #需要还原
            return False
            
        mx = sum(passingFees)
        low, high = passingFees[0], mx
        while low <= high:
            mid = (low+high) // 2
            vis = [0]*n
            if dfs(0, 0, passingFees[0]):
                high = mid-1
            else:
                low = mid+1
        return low if low <= mx else -1
    
class Solution1:
    def minCost(self, maxTime, edges, passingFees):
        from heapq import heappop, heappush
        n = len(passingFees)
        g = [[] for _ in range(n)]
        for x, y, t in edges:
            g[x].append((y, t))
            g[y].append((x, t))

        dis = [[float("inf")] * (maxTime + 1) for _ in range(n)]
        dis[0][0] = passingFees[0]
        h = [(dis[0][0], 0, 0)]
        while h:
            cost, x, time = heappop(h)
            for y, dt in g[x]:
                new_cost = cost + passingFees[y]
                new_time = time + dt
                if new_time <= maxTime and new_cost < dis[y][new_time]:
                    dis[y][new_time] = new_cost
                    heappush(h, (new_cost, y, new_time))
        ans = min(dis[-1])
        return ans if ans < float("inf") else -1

class Solution2:
    def minCost(self, maxTime, edges, passingFees):
        n = len(passingFees)
        dis = [[float("inf")]*n for _ in range(maxTime+1)]
        dis[0][0] = passingFees[0]

        for _ in range(n-1): #全为正可以省略迭代步骤
            updated = False
            for t in range(1, maxTime+1):
                for u, v, w in edges:
                    if t >= w:
                        if dis[t-w][v]+passingFees[u] < dis[t][u]: 
                            dis[t][u] = dis[t-w][v]+passingFees[u]
                            updated = True
                        if dis[t-w][u]+passingFees[v] < dis[t][v]:
                            dis[t][v] = dis[t-w][u]+passingFees[v]
                            updated = True
            if not updated:
                break
        ans = min(dis[i][-1] for i in range(1, maxTime+1))
        return ans if ans < float("inf") else -1 

